ucs.kql:
let lure_window = 30m;
let kyc_terms = dynamic(["utility","driver","licen","credit","passport","selfie","scan","photo","kyc","proof","invoice","statement","id_","id-"]);
let lures =
    DeviceFileEvents
    | where Timestamp > ago(7d)
    | where (FileName endswith ".lnk" or FileName endswith ".zip")
    | where FolderPath has_any (@"\Downloads\", @"\Temp\", @"\AppData\Local\Temp\")
    | where FileName has_any (kyc_terms)
    | project DeviceId, DeviceName, LureFile=FileName, LurePath=FolderPath, LureTime=Timestamp;
let jschain =
    DeviceProcessEvents
    | where Timestamp > ago(7d)
    | where FileName in~ ("wscript.exe","cscript.exe")
    | where InitiatingProcessFileName in~ ("explorer.exe","cmd.exe")
    | where ProcessCommandLine has_any (".js ", ".jse", ".wsf", ".vbs")
    | project DeviceId, ScriptHost=FileName, ScriptCmd=ProcessCommandLine, ScriptParent=InitiatingProcessFileName, ScriptTime=Timestamp, AccountName;
lures
| join kind=inner jschain on DeviceId
| where ScriptTime between (LureTime .. LureTime + lure_window)
| project LureTime, ScriptTime, DeviceName, AccountName, LureFile, LurePath, ScriptHost, ScriptParent, ScriptCmd
